module SR_latch (
    input wire SR_S,
    input wire R,
    output reg Q,
    output reg Q_not
);

always @(SR_S or R) begin
    if (SR_S && !R) begin
        Q = 1;
        Q_not = 0;
    end
    else if (!SR_S && R) begin
        Q = 0;
        Q_not = 1;
    end
    // Retain previous state if both are low
end

endmodule
